sql:
SELECT AVG(age) AS average_age
FROM employees
WHERE office_id = (SELECT office_id FROM offices WHERE office_name = 'Edinburgh');

SELECT COUNT(*) AS sick_leave_count
FROM time_off
WHERE type = 'sick leave';

SELECT first_name || ' ' || last_name AS full_name
FROM employees
ORDER BY full_name;

SELECT office_name
FROM offices
ORDER BY office_name ASC;

SELECT employee_id
FROM security_clearances
WHERE level = 'Top Secret';

external_knowledge:
- A 'Master's degree' is a postgraduate degree; 
- 'Edinburgh' and 'London' refer to cities in the United Kingdom; 
- "average salary of more than $50,000" implies an average annual salary that exceeds fifty thousand US dollars.

sql:
SELECT first_name, last_name
FROM employees
WHERE office_id = (SELECT office_id FROM offices WHERE office_name = 'Edinburgh');

SELECT DISTINCT employee_id
FROM certifications
WHERE expiry_date >= DATE('now');

external_knowledge:
; Hierarchical level refers to the level of an employee in the organizational chart, with lower levels indicating more senior positions; 
; A running total or cumulative sum is a calculation that adds up a sequence of numbers, with each new total being the sum of the previous total and the next number in the sequence;
; Departmental statistics include the number of employees and average salary for each department.

sql:
SELECT employee_id, MAX(change_date) AS latest_salary_change
FROM salary_changes
GROUP BY employee_id;

SELECT DISTINCT d.department_name
FROM departments d
JOIN employees e ON d.manager_id = e.employee_id;

SELECT AVG(new_salary) AS average_salary_change
FROM salary_changes
WHERE change_date BETWEEN '2015-01-01' AND '2015-12-31';
